const CATEGORIAS = ["Todas", ...new Set(CARTELES.map(c => c.categoria))];

// Convierte cualquier link de Drive al formato directo para mostrar como imagen
// Acepta link normal:  https://drive.google.com/file/d/ID/view
// Lo convierte a:      https://drive.google.com/uc?export=view&id=ID
function getDriveImageUrl(url) {
  if (!url) return null;
  if (url.includes("drive.google.com/uc?")) return url;
  const match = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if (match) return `https://drive.google.com/uc?export=view&id=${match[1]}`;
  return url;
}

function CartelCard({ cartel, onClick }) {
  const [hovered, setHovered] = useState(false);
  const [imgError, setImgError] = useState(false);
  const imgUrl = getDriveImageUrl(cartel.imagen_url);

  return (
    <div
      onClick={() => onClick(cartel)}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: "#fff",
        borderRadius: "16px",
        overflow: "hidden",
        cursor: "pointer",
        boxShadow: hovered ? "0 20px 60px rgba(0,0,0,0.15)" : "0 2px 16px rgba(0,0,0,0.07)",
        transform: hovered ? "translateY(-6px)" : "translateY(0)",
        transition: "all 0.25s cubic-bezier(0.34,1.56,0.64,1)",
        border: "1px solid #f0f0f0",
      }}
    >
      <div style={{
        background: cartel.color,
        height: "160px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        overflow: "hidden",
      }}>
        {imgUrl && !imgError
          ? <img
              src={imgUrl}
              onError={() => setImgError(true)}
              style={{ width: "100%", height: "160px", objectFit: "cover", display: "block" }}
              alt={cartel.nombre}
            />
          : <span style={{ fontSize: "64px", filter: "drop-shadow(0 4px 12px rgba(0,0,0,0.15))" }}>{cartel.emoji}</span>
        }
        <div style={{
          position: "absolute", top: "12px", right: "12px",
          background: "rgba(255,255,255,0.9)", borderRadius: "8px",
          padding: "3px 10px", fontSize: "11px", fontWeight: "600",
          color: "#333", letterSpacing: "0.5px",
        }}>
          {cartel.formato}
        </div>
      </div>

      <div style={{ padding: "16px" }}>
        <div style={{ fontSize: "13px", color: "#888", marginBottom: "4px", fontWeight: "500" }}>
          {cartel.categoria}
        </div>
        <div style={{ fontSize: "16px", fontWeight: "700", color: "#1a1a1a", marginBottom: "10px", lineHeight: 1.3 }}>
          {cartel.nombre}
        </div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: "5px" }}>
          {cartel.tags.map(tag => (
            <span key={tag} style={{
              background: "#fff9e6", border: "1px solid #FFE600",
              color: "#7a6000", borderRadius: "20px", padding: "2px 10px",
              fontSize: "11px", fontWeight: "600",
            }}>
              {tag}
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

function Modal({ cartel, onClose }) {
  const [imgError, setImgError] = useState(false);
  if (!cartel) return null;
  const imgUrl = getDriveImageUrl(cartel.imagen_url);

  return (
    <div onClick={onClose} style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)",
      display: "flex", alignItems: "center", justifyContent: "center",
      zIndex: 1000, padding: "20px", backdropFilter: "blur(4px)",
    }}>
      <div onClick={e => e.stopPropagation()} style={{
        background: "#fff", borderRadius: "24px", maxWidth: "520px",
        width: "100%", overflow: "hidden", boxShadow: "0 40px 100px rgba(0,0,0,0.3)",
      }}>
        <div style={{
          background: cartel.color, height: "200px",
          display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden",
        }}>
          {imgUrl && !imgError
            ? <img
                src={imgUrl}
                onError={() => setImgError(true)}
                style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }}
                alt={cartel.nombre}
              />
            : <span style={{ fontSize: "90px" }}>{cartel.emoji}</span>
          }
        </div>

        <div style={{ padding: "28px" }}>
          <div style={{ fontSize: "13px", color: "#999", marginBottom: "4px", fontWeight: "500", textTransform: "uppercase", letterSpacing: "1px" }}>
            {cartel.categoria} · {cartel.subcategoria}
          </div>
          <h2 style={{ margin: "0 0 8px 0", fontSize: "24px", fontWeight: "800", color: "#1a1a1a" }}>
            {cartel.nombre}
          </h2>
          <p style={{ margin: "0 0 16px 0", color: "#666", fontSize: "14px", lineHeight: 1.6 }}>
            {cartel.notas}
          </p>

          <div style={{ background: "#f5f5f5", borderRadius: "10px", padding: "10px 16px", marginBottom: "20px", display: "inline-block" }}>
            <div style={{ fontSize: "11px", color: "#999", fontWeight: "600", marginBottom: "2px" }}>FORMATO</div>
            <div style={{ fontSize: "15px", fontWeight: "700", color: "#1a1a1a" }}>{cartel.formato}</div>
          </div>

          <div style={{ display: "flex", flexWrap: "wrap", gap: "6px", marginBottom: "24px" }}>
            {cartel.tags.map(tag => (
              <span key={tag} style={{
                background: "#fff9e6", border: "1px solid #FFE600",
                color: "#7a6000", borderRadius: "20px", padding: "4px 12px",
                fontSize: "12px", fontWeight: "600",
              }}>{tag}</span>
            ))}
          </div>

          <a
            href={cartel.carpeta_drive}
            target="_blank"
            rel="noreferrer"
            style={{
              display: "flex", alignItems: "center", justifyContent: "center", gap: "8px",
              background: "#FFE600", color: "#1a1a1a", borderRadius: "12px",
              padding: "14px", fontSize: "15px", fontWeight: "700",
              textDecoration: "none", marginBottom: "10px",
            }}
          >
            📁 Ver originales en Drive
          </a>
          <button onClick={onClose} style={{
            width: "100%", padding: "12px", borderRadius: "12px",
            border: "1.5px solid #e0e0e0", background: "transparent",
            color: "#666", fontSize: "14px", fontWeight: "600", cursor: "pointer",
          }}>
            Cerrar
          </button>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.cdnfonts.com/css/proxima-nova-2";
    document.head.appendChild(link);
  }, []);

  const [busqueda, setBusqueda] = useState("");
  const [categoriaActiva, setCategoriaActiva] = useState("Todas");
  const [modalCartel, setModalCartel] = useState(null);

  const filtrados = useMemo(() => {
    return CARTELES.filter(c => {
      const matchCat = categoriaActiva === "Todas" || c.categoria === categoriaActiva;
      const q = busqueda.toLowerCase();
      const matchQ = !q || c.nombre.toLowerCase().includes(q) || c.tags.some(t => t.includes(q)) || c.categoria.toLowerCase().includes(q);
      return matchCat && matchQ;
    });
  }, [busqueda, categoriaActiva]);

  return (
    <div style={{ minHeight: "100vh", background: "#f7f7f7", fontFamily: "'Proxima Nova', 'Helvetica Neue', Helvetica, Arial, sans-serif" }}>
      {/* Header */}
      <div style={{ background: "#FFE600", padding: "0 32px" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "20px 0", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "14px" }}>
            <img src={ISO_LOGO} alt="MercadoLibre" style={{ height: "56px", width: "auto" }} />
            <div>
              <div style={{ fontSize: "18px", fontWeight: "800", color: "#1a1a1a", lineHeight: 1 }}>Catálogo de Cartelería</div>
              <div style={{ fontSize: "12px", color: "rgba(0,0,0,0.5)", fontWeight: "500", marginTop: "2px" }}>Marketing Envíos · {CARTELES.length} carteles</div>
            </div>
          </div>
          <div style={{ fontSize: "13px", fontWeight: "600", color: "rgba(0,0,0,0.4)" }}>
            Powered by Omelet
          </div>
        </div>
      </div>

      {/* Search + Filters */}
      <div style={{ background: "#fff", borderBottom: "1px solid #eee", padding: "0 32px", position: "sticky", top: 0, zIndex: 100 }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "16px 0", display: "flex", flexDirection: "column", gap: "12px" }}>
          <div style={{ position: "relative" }}>
            <span style={{ position: "absolute", left: "14px", top: "50%", transform: "translateY(-50%)", fontSize: "16px" }}>🔍</span>
            <input
              placeholder="Buscar cartel, categoría o tag..."
              value={busqueda}
              onChange={e => setBusqueda(e.target.value)}
              style={{
                width: "100%", padding: "12px 16px 12px 42px",
                borderRadius: "12px", border: "1.5px solid #e0e0e0",
                fontSize: "14px", fontWeight: "500", outline: "none",
                boxSizing: "border-box", background: "#fafafa",
              }}
              onFocus={e => e.target.style.borderColor = "#FFE600"}
              onBlur={e => e.target.style.borderColor = "#e0e0e0"}
            />
          </div>
          <div style={{ display: "flex", gap: "8px", overflowX: "auto", paddingBottom: "2px" }}>
            {CATEGORIAS.map(cat => (
              <button
                key={cat}
                onClick={() => setCategoriaActiva(cat)}
                style={{
                  padding: "7px 16px", borderRadius: "20px", border: "none",
                  background: categoriaActiva === cat ? "#1a1a1a" : "#f0f0f0",
                  color: categoriaActiva === cat ? "#FFE600" : "#666",
                  fontSize: "12px", fontWeight: "700", cursor: "pointer",
                  whiteSpace: "nowrap", transition: "all 0.2s", letterSpacing: "0.3px",
                }}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Grid */}
      <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "32px" }}>
        {filtrados.length === 0 ? (
          <div style={{ textAlign: "center", padding: "80px 0", color: "#999" }}>
            <div style={{ fontSize: "48px", marginBottom: "16px" }}>🔍</div>
            <div style={{ fontSize: "18px", fontWeight: "600" }}>No encontramos carteles con esa búsqueda</div>
          </div>
        ) : (
          <>
            <div style={{ fontSize: "13px", color: "#999", marginBottom: "20px", fontWeight: "500" }}>
              {filtrados.length} {filtrados.length === 1 ? "cartel" : "carteles"} encontrados
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))", gap: "20px" }}>
              {filtrados.map(cartel => (
                <CartelCard key={cartel.id} cartel={cartel} onClick={setModalCartel} />
              ))}
            </div>
          </>
        )}
      </div>

      <Modal cartel={modalCartel} onClose={() => setModalCartel(null)} />
    </div>
  );
}
